<?php declare(strict_types=1);require __DIR__.'/bootstrap.php';use VP3\Installation\InstallationJobService;$pageTitle='Hosting';$customer=vp3_require_customer();if(vp3_method()==='POST'){vp3_verify_csrf();$hostingUuid=vp3_input('hosting_uuid');if(vp3_db_available()){$stmt=vp3_db()->prepare('SELECT id FROM hosting_accounts WHERE hosting_uuid=? AND customer_id=?');$stmt->execute([$hostingUuid,$customer['id']]);$hostingId=(int)($stmt->fetchColumn()?:0);if($hostingId){$service=new InstallationJobService(vp3_db());$service->queue($hostingId,null);vp3_flash('success','Installation job queued.');}}vp3_redirect('account-hosting.php');}require VP3_ROOT.'/includes/account-header.php';$rows=[];if(vp3_db_available()){$stmt=vp3_db()->prepare('SELECT h.*,p.name product_name,ij.job_uuid,ij.job_status,ij.current_step,ij.progress_percent,bs.subscription_status,bs.current_period_end FROM hosting_accounts h JOIN products p ON p.id=h.product_id LEFT JOIN billing_subscriptions bs ON bs.id=(SELECT MAX(bs2.id) FROM billing_subscriptions bs2 WHERE bs2.hosting_account_id=h.id) LEFT JOIN installation_jobs ij ON ij.id=(SELECT MAX(i2.id) FROM installation_jobs i2 WHERE i2.hosting_account_id=h.id) WHERE h.customer_id=? ORDER BY h.id DESC');$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();}?><h1>Hosted platforms</h1><div class="grid two"><?php foreach($rows as $r):?><article class="card"><span class="badge <?=vp3_e($r['hosting_status'])?>"><?=vp3_e($r['hosting_status'])?></span><h3><?=vp3_e($r['product_name'])?></h3><p><?=vp3_e($r['subdomain'].'.'.vp3_config('hosting.base_domain'))?></p><p>Install: <?=vp3_e($r['installation_status'])?> · <?=vp3_e((string)$r['progress_percent'])?>%</p><?php if($r['job_status']):?><div class="progress"><span style="width:<?=max(0,min(100,(int)$r['progress_percent']))?>%"></span></div><small><?=vp3_e($r['current_step'])?></small><?php endif;?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="hosting_uuid" value="<?=vp3_e($r['hosting_uuid'])?>"><button class="button small" type="submit">Launch / retry installation</button></form></article><?php endforeach;?><?php if(!$rows):?><p>No hosted platforms yet.</p><?php endif;?></div><?php require VP3_ROOT.'/includes/account-footer.php';?>